const btn = document.getElementById('combo-btn');
const list = document.getElementById('combo-list');
const options = Array.from(list.querySelectorAll('li'));

let isOpen = false;
let activeIndex = -1;

function setOpen(val) {
  isOpen = val;
  btn.setAttribute('aria-expanded', val.toString());
  list.classList.toggle('hidden', !val);
  if (!val) {
    activeIndex = -1;
    options.forEach(opt => opt.classList.remove('bg-indigo-600', 'text-white'));
  }
}

btn.addEventListener('click', () => {
  setOpen(!isOpen);
});

document.addEventListener('keydown', (e) => {
  if (!isOpen) return;

  if (e.key === 'Escape') {
    setOpen(false);
    btn.focus();
  } else if (e.key === 'ArrowDown') {
    e.preventDefault();
    activeIndex = (activeIndex + 1) % options.length;
    highlightOption();
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    activeIndex = (activeIndex - 1 + options.length) % options.length;
    highlightOption();
  } else if (e.key === 'Enter') {
    if (activeIndex >= 0) {
      e.preventDefault();
      selectOption(activeIndex);
    }
  }
});

function highlightOption() {
  options.forEach((opt, idx) => {
    const active = idx === activeIndex;
    opt.classList.toggle('bg-indigo-600', active);
    opt.classList.toggle('text-white', active);
  });
}

function selectOption(index) {
  btn.querySelector('span').textContent = options[index].textContent;
  setOpen(false);
  btn.focus();
}

options.forEach((opt, index) => {
  opt.addEventListener('click', () => {
    selectOption(index);
  });
});
